typedef struct { int x,y,life,active; } Wall;
typedef struct { int corrupt, enemyMask, target, timeLimit, magnet, boss; const char *name; const char *story; } Stage;
typedef struct { int score, level, lives, energy, combo, maxCombo, repairs, protectedSaved, player; } RunStats;

